const express = require('express');
const puppeteer = require('puppeteer');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;

const BANCO_PATH = path.join(__dirname, 'banco_produtos.json');
const CONFIG_PATH = path.join(__dirname, 'config_atacado.json');

app.use(express.json());
// Servir arquivos estáticos da pasta "public"
app.use(express.static(path.join(__dirname, 'public')));

// Inicialização segura de arquivos locais
if (!fs.existsSync(BANCO_PATH)) fs.writeFileSync(BANCO_PATH, JSON.stringify([], null, 2));
if (!fs.existsSync(CONFIG_PATH)) {
    fs.writeFileSync(CONFIG_PATH, JSON.stringify({
        whatsappAdmin: "5511915184857",
        nomeLoja: "NEOPODER.SHOP",
        urlFornecedor: "https://goatatacadoesportivo.com/",
        lucro: [
            { id: "at_3", nome: "Atacado Base", margemFixa: 17.00 }
        ]
    }, null, 2));
}

// Rota principal: Envia a interface gráfica para o usuário
app.get('/', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// APIs de comunicação da tabela
app.get('/api/dados', (req, res) => {
    const produtos = JSON.parse(fs.readFileSync(BANCO_PATH, 'utf-8'));
    const config = JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf-8'));
    res.json({ produtos, config });
});

app.post('/api/salvar', (req, res) => {
    const { produtos } = req.body;
    if (produtos) fs.writeFileSync(BANCO_PATH, JSON.stringify(produtos, null, 2));
    res.json({ success: true });
});

// Robô de varredura otimizado para servidores gratuitos (Baixo consumo de RAM)
async function varrerCatalogoOtimizado() {
    console.log("🤖 [ROBÔ] Iniciando varredura leve de segurança...");
    let browser;
    try {
        const config = JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf-8'));
        let banco = JSON.parse(fs.readFileSync(BANCO_PATH, 'utf-8'));

        browser = await puppeteer.launch({
            headless: "new",
            args: [
                '--no-sandbox', 
                '--disable-setuid-sandbox', 
                '--disable-dev-shm-usage', 
                '--disable-gpu'
            ]
        });

        const page = await browser.newPage();
        // Bloqueia mídias pesadas para economizar a banda e a RAM do servidor gratuito
        await page.setRequestInterception(true);
        page.on('request', (req) => {
            if (['image', 'stylesheet', 'font', 'media'].includes(req.resourceType())) {
                req.abort();
            } else {
                req.continue();
            }
        });

        // Varre apenas as principais ofertas para não estourar os limites gratuitos
        await page.goto(config.urlFornecedor, { waitUntil: 'domcontentloaded', timeout: 20000 });
        
        const itensMapeados = await page.evaluate(() => {
            const itens = [];
            document.querySelectorAll('.product-item, .produto, .card, li').forEach(card => {
                const nome = card.querySelector('h1, h2, h3, .title, .name, [class*="name"]')?.innerText?.trim();
                let precoRaw = card.querySelector('.price, .preco, [class*="price"]')?.innerText?.trim();
                
                if (!precoRaw && card.innerText.includes('R$')) {
                    precoRaw = 'R$ ' + card.innerText.split('R$')[1].split('\n')[0].trim();
                }

                const imgEl = card.querySelector('img');
                const img = imgEl ? (imgEl.getAttribute('data-src') || imgEl.src || '') : '';

                if (nome && precoRaw && nome.length > 4) {
                    itens.push({ nome, precoRaw, img });
                }
            });
            return itens;
        });

        itensMapeados.forEach(prod => {
            const precoNumerico = parseFloat(prod.precoRaw.replace(/[^\d,.]/g, '').replace('.', '').replace(',', '.'));
            if (isNaN(precoNumerico) || precoNumerico <= 0) return;

            const idUnico = Buffer.from(prod.nome).toString('base64').substring(0, 10);
            if (!banco.some(p => p.id === idUnico)) {
                banco.push({
                    id: idUnico,
                    nome: prod.nome,
                    img: prod.img || 'https://via.placeholder.com/400x500?text=Camisa',
                    custo: precoNumerico,
                    categoria: "Camisas de Time",
                    esgotado: false
                });
            }
        });

        fs.writeFileSync(BANCO_PATH, JSON.stringify(banco, null, 2));
        console.log(`✅ [ROBÔ] Varredura concluída com sucesso. Itens na base: ${banco.length}`);

    } catch (err) {
        console.log("⚠️ Erro na varredura provisória:", err.message);
    } finally {
        if (browser) await browser.close();
    }
}

// Executa a varredura inicial assim que o servidor acorda
app.listen(PORT, () => {
    console.log(`🚀 Servidor provisório rodando na porta ${PORT}`);
    varrerCatalogoOtimizado();
});